class Solution:
    def maximumCount(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        def is_prime(n):
            if n < 2:
                return False
            for i in range(2, int(n**0.5) + 1):
                if n % i == 0:
                    return False
            return True

        result = []
        for idx, val in queries:
            nums[idx] = val
            max_count = 0
            for k in range(1, len(nums)):
                prefix = set(num for num in nums[:k] if is_prime(num))
                suffix = set(num for num in nums[k:] if is_prime(num))
                max_count = max(max_count, len(prefix) + len(suffix))
            result.append(max_count)
        return result
